INSERT INTO `basic_gu_insect` VALUES ('2014606943468912640', '希望蛊', NULL, NULL, NULL, '外形呈光点状，核心功能为帮助蛊师开启体内空窍以奠定修行根基。其以“希望”为意象，象征心灵力量对现实困境的突破，相较于依赖青春或智慧的其他蛊虫，仅需精神寄托即可激活，突显超越肉体与智谋的精神内核。', 0, 40, 5, 2147483647, 'sys_user', '2026-01-23 15:52:07', 'sys_user', '2026-01-27 15:54:42');
INSERT INTO `basic_gu_insect` VALUES ('2016056972742230016', '寿蛊（十年）', NULL, NULL, NULL, '能增添新的十年寿命', 0, 40, 2, 2147483647, 'sys_user', '2026-01-23 15:52:07', 'sys_user', '2026-01-23 15:52:07');
INSERT INTO `basic_gu_insect` VALUES ('2016070981428183040', '寿蛊（百年）', NULL, NULL, NULL, '能增添新的百年寿命', 0, 40, 3, 2147483647, 'sys_user', '2026-01-27 16:49:13', 'sys_user', '2026-01-27 16:49:13');
INSERT INTO `basic_gu_insect` VALUES ('2016071150777401344', '寿蛊（千年）', NULL, NULL, NULL, '能增添新的千年寿命', 0, 40, 4, 2147483647, 'sys_user', '2026-01-27 16:49:13', 'sys_user', '2026-01-27 16:49:13');
INSERT INTO `basic_gu_insect` VALUES ('2016418182130040832', '智慧蛊', 'http://localhost:8088/umr/files/2026/01/28/2016434435922067456.png', 'http://localhost:8088/umr/files/2026/01/28/2016439265763786752.png', '', '六转到九转。\n能引导他人开智激发灵感，是思想蛊的孩子。\n使用需要付出寿命。\n智慧蛊说它只臣服于比它更智慧的存在，推测是只能被比它更有智慧的人炼化', 1, 40, 9, 1, 'sys_user', '2026-01-28 15:48:57', NULL, '2026-01-28 17:29:18');
INSERT INTO `basic_gu_insect` VALUES ('2017125870321270784', '天气蛊', '', '', '', 'test', 0, 4, 1, 2147483647, 'sys_user', '2026-01-30 14:40:59', 'sys_user', '2026-01-30 14:40:59');
INSERT INTO `basic_gu_insect` VALUES ('2017154401151483904', '自己蛊', '', '', '', '自己蛊是属于自己的', 1, 40, 9, 1, 'sys_user', '2026-01-30 16:34:21', 'sys_user', '2026-01-30 16:34:21');
INSERT INTO `basic_gu_insect` VALUES ('2017161643540086784', '力量蛊', '', '', '', '', 1, 7, 9, 1, 'sys_user', '2026-01-30 17:03:08', 'sys_user', '2026-01-30 17:03:08');
