  INDEX `user_name_index`(`user_name` ASC) USING BTREE COMMENT '加速查询'
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户信息表' ROW_FORMAT = DYNAMIC;

